#!/usr/bin/env python3"""Plot a Google Benchmark JSON run as a grouped vertical bar chart.Usage:    python plot_bench.py <results.json> [-o out] [--metric items_per_second]Benchmark names are split on the last '/' into "<category>/<series>", soregistrations like  vec4_add/nme  vec4_add/glm  become grouped bars per op.With --benchmark_report_aggregates_only the median aggregate is the plottedvalue and the stddev aggregate (if present) is drawn as error bars -- run with--benchmark_repetitions=N to get it. Without aggregates, the raw run is used andthere are no error bars. Saves <out>.png and <out>.svg. Uses a log y-axisautomatically when the value range spans more than ~30x (e.g. vec ops vs mat opsin one chart)."""import argparse, json, sysfrom collections import OrderedDictimport matplotlibmatplotlib.use("Agg")import matplotlib.pyplot as pltimport numpy as npPALETTE = ["#2a78d6", "#1baf7a", "#eda100", "#4a3aa7", "#e34948", "#eb6834"]def load(path, metric):    with open(path) as f:        entries = json.load(f)["benchmarks"]    vals, errs = {}, {}  # run_name -> median value / stddev    for e in entries:        name = e.get("run_name", e["name"])        agg = e.get("aggregate_name")        # aggregates run: keep median (the value) and stddev (the error); drop        # mean/cv. Non-aggregate (raw) runs have no aggregate_name -> value.        if e.get("run_type") == "aggregate" and agg not in ("median", "stddev"):            continue        if metric in e:            (errs if agg == "stddev" else vals)[name] = e[metric]    return vals, errsdef main():    ap = argparse.ArgumentParser()    ap.add_argument("json")    ap.add_argument("-o", "--out", default="bench")    ap.add_argument("--metric", default="items_per_second")    ap.add_argument("--title", default="benchmark throughput")    args = ap.parse_args()    vals, errs = load(args.json, args.metric)    if not vals:        sys.exit(f"no '{args.metric}' values found in {args.json}")    cats, series = OrderedDict(), OrderedDict()    for name in vals:        cat, _, s = name.rpartition("/")        cat = cat or name        cats.setdefault(cat, {})[s] = vals[name]        series.setdefault(s, None)    cat_names, ser_names = list(cats), list(series)    scale = 1e6 if args.metric == "items_per_second" else 1.0  # -> millions    data = np.array([[cats[c].get(s, 0) / scale for c in cat_names] for s in ser_names])    # error matrix parallels `data`; key is the full run_name (cat + '/' + series).    err = np.array([[errs.get(f"{c}/{s}", 0.0) / scale for c in cat_names] for s in ser_names])    has_err = err.any()    fig, ax = plt.subplots(figsize=(max(6, 1.6 * len(cat_names)), 5))    x = np.arange(len(cat_names))    w = 0.8 / max(1, len(ser_names))    for i, s in enumerate(ser_names):        off = (i - (len(ser_names) - 1) / 2) * w        bars = ax.bar(x + off, data[i], w, color=PALETTE[i % len(PALETTE)],                      label=s, zorder=3,                      yerr=(err[i] if has_err else None),                      capsize=2, error_kw={"elinewidth": 0.8, "zorder": 4})        ax.bar_label(bars, fmt="%.0f", padding=2, fontsize=8, color="#333")    hi, lo = data[data > 0].max(), data[data > 0].min()    if hi / lo > 30:        ax.set_yscale("log")    ax.set_xticks(x); ax.set_xticklabels(cat_names, fontsize=9)    unit = "million ops / s" if args.metric == "items_per_second" else args.metric    ax.set_ylabel(f"{unit}  (higher is better)", fontsize=10)    ax.set_title(args.title, fontsize=12, loc="left")    ax.grid(axis="y", color="#e1e0d9", zorder=0); ax.set_axisbelow(True)    for sp in ("top", "right"):        ax.spines[sp].set_visible(False)    ax.legend(frameon=False, ncol=len(ser_names), fontsize=9,              loc="upper center", bbox_to_anchor=(0.5, 1.12))    ax.margins(y=0.15)    plt.tight_layout()    for ext in ("png", "svg"):        fig.savefig(f"{args.out}.{ext}", dpi=150, bbox_inches="tight")    print(f"wrote {args.out}.png and {args.out}.svg")if __name__ == "__main__":    main()